  // Aquí simulamos que algunos turnos ya están ocupados para que veas el efecto
  const [occupiedSlots, setOccupiedSlots] = useState<OccupiedSlot[]>([
    { date: new Date(Date.now() + 86400000).toISOString().split('T')[0], time: '10:00' },
    { date: new Date(Date.now() + 86400000).toISOString().split('T')[0], time: '16:00' },
    { date: new Date(Date.now() + 172800000).toISOString().split('T')[0], time: '09:00' }
  ]);

  const dates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() + i + 1);
    return {
      iso: d.toISOString().split('T')[0],
      day: d.toLocaleDateString('es-ES', { weekday: 'short' }),
      num: d.getDate(),
      month: d.toLocaleDateString('es-ES', { month: 'short' })
    };
  });

  const timeSlots = [
    '09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00', '18:00'
  ];

  const isSlotOccupied = (date: string, time: string) => {
    return occupiedSlots.some(slot => slot.date === date && slot.time === time);
  };

  const handleNextStep = () => {
    if (step < 3) setStep(step + 1);
    else {
      const appointment: Appointment = {
        id: Math.random().toString(36).substr(2, 9),
        serviceId: service.id,
        serviceName: service.name,
        date: selectedDate,
        time: selectedTime,
        userName,
        userPhone
      };

      // Enviar a WhatsApp
      const message = `Hola En Armonía! Me gustaría confirmar un turno para:
- Servicio: ${service.name}
- Fecha: ${selectedDate}
- Hora: ${selectedTime}hs
- Nombre: ${userName}
- Tel: ${userPhone}`;

      const whatsappUrl = `https://wa.me/5491100000000?text=${encodeURIComponent(message)}`;
      window.open(whatsappUrl, '_blank');

      onConfirm(appointment);
    }
  };

  return (
    <div className="p-6">
      <div className="flex items-center gap-3 mb-8 pt-4">
        <button onClick={onCancel} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
        </button>
        <h2 className="text-xl font-bold text-[#4A4A4A]">Agendar Turno</h2>
      </div>

