                  {timeSlots.map((t) => {
                    const occupied = isSlotOccupied(selectedDate, t);
                    return (
                      <button
                        key={t}
                        disabled={occupied}
                        onClick={() => setSelectedTime(t)}
                        className={`py-3 rounded-xl border text-sm font-semibold transition-all relative ${
                          occupied 
