        });
        setAllAppointments(appointments);
        setDbError(null);
      },
      (error) => {
        console.error("Error en Firestore:", error);
        if (error.code === 'permission-denied') {
          setDbError("Error de permisos: Por favor, configura las reglas de Firestore en la consola de Firebase.");
