                <span className="font-bold text-[#4A4A4A] text-right ml-4">{service.name}</span>
              </div>
              <div className="flex justify-between items-center border-b border-gray-200/50 pb-2">
                <span className="text-gray-400 font-medium">Fecha y Hora:</span>
                <span className="font-bold text-[#4A4A4A] uppercase text-[10px]">{selectedDate} — {selectedTime}HS</span>
              </div>
              <div className="flex justify-between items-center border-b border-gray-200/50 pb-2">
                <span className="text-gray-400 font-medium">Nombre:</span>
                <span className="font-bold text-[#4A4A4A]">{userName || '---'}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-400 font-medium">Contacto:</span>
                <span className="font-bold text-[#4A4A4A]">{userPhone || '---'}</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <button 
        disabled={
          (step === 1 && (!selectedDate || !selectedTime)) ||
          (step === 2 && (userName.trim().length < 3 || userPhone.trim().length < 7))
        }
        onClick={handleNextStep}
        className={`w-full py-4 rounded-2xl font-bold text-white shadow-lg transition-all active:scale-[0.98] ${
          ((step === 1 && (!selectedDate || !selectedTime)) || (step === 2 && (userName.trim().length < 3 || userPhone.trim().length < 7)))
            ? 'bg-gray-200 cursor-not-allowed shadow-none'
